package com.meltwater.fhai.crawler.quiddityconverter.dto;

import java.io.IOException;

import com.fasterxml.jackson.core.JsonParser;
import com.fasterxml.jackson.databind.DeserializationContext;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.deser.std.StdDeserializer;

public class ArticleDataDeserializer extends StdDeserializer<ArticleData> {

    public ArticleDataDeserializer() {
        this(null);
    }

    public ArticleDataDeserializer(Class<?> vc) {
        super(vc);
    }

    @Override
    public ArticleData deserialize(JsonParser p, DeserializationContext ctxt) {
        try {
            JsonNode jsonNode = locateArticleData(p.getCodec().readTree(p));
            return p.getCodec().treeToValue(jsonNode, ArticleData.class);
        } catch (IOException e) {
            throw new RuntimeException("Cannot convert resource to ArticleData: " + e.getMessage(), e);
        }
    }

    private JsonNode locateArticleData(JsonNode rootNode) {
        JsonNode extractionResult = get(rootNode, "extractionResult");
        return get(extractionResult, "content");
    }

    private JsonNode get(JsonNode rootNode, String name) {
        JsonNode node = rootNode.get(name);
        if (node == null || node.isNull()) {
            throw new RuntimeException(name + " not found or null");
        }
        return node;
    }

}

