package com.meltwater.fhai.crawler.quiddityconverter.gateway.scheduler;

import com.meltwater.fhai.sourceconfiguration.GenericSourceConfiguration;

import lombok.Data;

import java.util.ArrayList;
import java.util.List;

@Data
public class RevolutionConfigsDTO {

    private GenericSourceConfiguration sourceConfig;
    private CrawlerConfiguration crawlerConfig;

    @Data
    public static class CrawlerConfiguration {
        private List<String> routingAttributes = new ArrayList<>();
        private DocumentConverter documentConverter;
        private Scheduler scheduler;
    }

    @Data
    public static class Scheduler {
        private boolean frontPageCrawlingEnabled;
    }

    @Data
    public static class DocumentConverter {
        private Boolean enrichSourceMetadata = true;
        private Boolean publisherOverwrite = false;
        private Boolean publishOnMissingDate;
        private List<String> documentLabels;
        private List<String> publisherAttributes = new ArrayList<>();
    }
}
